#define BLOCK_SIZE 256
#define HALO 1

__kernel void dynproc_kernel(
    int iteration,
    __global int* gpuWall,
    __global int* gpuSrc,
    __global int* gpuResults,
    int cols,
    int rows,
    int startStep,
    int border,
    int theHalo,
    __local int* prev,
    __local int* result
) {
    int bx = get_group_id(0);
    int tx = get_local_id(0);

    int small_block_cols = BLOCK_SIZE - iteration * theHalo * 2;

    int blkX = small_block_cols * bx - border;
    int blkXmax = blkX + BLOCK_SIZE - 1;

    int xidx = blkX + tx;

    int validXmin = (blkX < 0) ? -blkX : 0;
    int validXmax = (blkXmax > cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - cols + 1) : BLOCK_SIZE - 1;

    int W = tx - 1;
    int E = tx + 1;

    W = (W < validXmin) ? validXmin : W;
    E = (E > validXmax) ? validXmax : E;

    int isValid = (tx >= validXmin && tx <= validXmax);

    if (xidx >= 0 && xidx < cols) {
        prev[tx] = gpuSrc[xidx];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    int computed = 0;
    for (int i = 0; i < iteration; i++) {
        computed = 0;
        if ((tx >= i + 1) && (tx <= BLOCK_SIZE - i - 2) && isValid) {
            computed = 1;
            int left = prev[W];
            int up = prev[tx];
            int right = prev[E];
            int shortest = left < up ? left : up;
            shortest = shortest < right ? shortest : right;
            int index = cols * (startStep + i) + xidx;
            result[tx] = shortest + gpuWall[index];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
        if (i == iteration - 1)
            break;
        if (computed)
            prev[tx] = result[tx];
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (computed) {
        gpuResults[xidx] = result[tx];
    }
}
